import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void basicQueriesWithNegatives() {
        // nums = [-2, 0, 3, -5, 2, -1]
        // prefix = [0, -2, -2, 1, -4, -2, -3]
        Solution sol = new Solution(new int[]{-2, 0, 3, -5, 2, -1});
        assertEquals(1,  sol.sumRange(0, 2));  // -2+0+3
        assertEquals(-1, sol.sumRange(2, 5));  // 3+(-5)+2+(-1)
        assertEquals(-3, sol.sumRange(0, 5));  // entire array
    }

    @Test
    void singleElementQuery() {
        Solution sol = new Solution(new int[]{4, 7, -3});
        assertEquals(4,  sol.sumRange(0, 0));
        assertEquals(7,  sol.sumRange(1, 1));
        assertEquals(-3, sol.sumRange(2, 2));
    }

    @Test
    void allPositives() {
        // nums = [1, 2, 3, 4, 5] → prefix = [0, 1, 3, 6, 10, 15]
        Solution sol = new Solution(new int[]{1, 2, 3, 4, 5});
        assertEquals(6,  sol.sumRange(0, 2));  // 1+2+3
        assertEquals(9,  sol.sumRange(1, 3));  // 2+3+4
        assertEquals(15, sol.sumRange(0, 4));  // entire array
    }

    @Test
    void multipleQueriesSameInstance() {
        // Verifies the prefix array is reused, not recomputed
        Solution sol = new Solution(new int[]{10, -10, 10, -10, 10});
        assertEquals(0,  sol.sumRange(0, 1));
        assertEquals(10, sol.sumRange(0, 0));
        assertEquals(10, sol.sumRange(0, 4));
        assertEquals(0,  sol.sumRange(1, 4));
    }

    @Test
    void singleElementArray() {
        Solution sol = new Solution(new int[]{42});
        assertEquals(42, sol.sumRange(0, 0));
    }

    @Test
    void allZeros() {
        Solution sol = new Solution(new int[]{0, 0, 0, 0});
        assertEquals(0, sol.sumRange(0, 3));
        assertEquals(0, sol.sumRange(1, 2));
    }
}
